//! The tamper-evident audit chain, driven through real fleet operations.
//!
//! Each lifecycle op (spawn, update, reap, delegate-spawn, oath-breach) emits a
//! signed, hash-linked entry to the audit chain (see `monster_swarm::audit`).
//! This drives those ops end to end (with a fake monster-guard so no real
//! runtime is needed, the same harness pattern as `trust_admission.rs` /
//! `oath_breach.rs`) and then:
//!   1. `audit::verify()` reports OK on the chain the ops produced.
//!   2. The expected EventKinds are present, in order, with the right subjects.
//!   3. Corrupting `audit.jsonl` on disk makes `verify()` detect the tamper.
//!
//! Each test owns a per-name temp `$MONSTER_GUARD_HOME`; they share the global
//! env so a mutex serializes them.

use std::os::unix::fs::PermissionsExt;
use std::path::PathBuf;
use std::sync::Mutex;

use a0n_auth::ucan::issue;
use a0n_auth::{Capability, IssueOptions};

use monster_swarm::audit::{self, EventKind};
use monster_swarm::budget::Caste;
use monster_swarm::ops::{
    self, BreachRequest, DelegateSpawnRequest, SpawnRequest, UpdateRequest, DEFAULT_GRANT_TTL_SECS,
};
use monster_swarm::store;

static ENV_GUARD: Mutex<()> = Mutex::new(());

/// Fake `monster-guard`: delegate + revoke exit 0; run stays alive briefly so the
/// supervisor pid is live when the ledger is saved.
fn fake_guard(dir: &PathBuf) -> PathBuf {
    let bin = dir.join("monster-guard");
    let script = "#!/bin/sh\n\
         if [ \"$1\" = \"run\" ]; then\n\
         \texec sleep 30\n\
         fi\n\
         exit 0\n";
    std::fs::write(&bin, script).unwrap();
    std::fs::set_permissions(&bin, std::fs::Permissions::from_mode(0o755)).unwrap();
    bin
}

fn fake_node(dir: &PathBuf) -> PathBuf {
    let node = dir.join("fake-node");
    std::fs::write(&node, "#!/bin/sh\nexit 0\n").unwrap();
    std::fs::set_permissions(&node, std::fs::Permissions::from_mode(0o755)).unwrap();
    node
}

/// A capability granting agent/spawn + agent/update + agent/reap rooted at the
/// resident root. The leaf aud (the holder/spawner DID) is the root's own DID.
/// reap also covers oath-breach (authorize uses the same `agent/reap`).
fn full_ucan() -> (String, String) {
    let root = store::ensure_root().expect("root");
    let caps = vec![
        Capability { can: "agent/spawn".into(), with: "agent:fleet".into(), constraints: None },
        Capability { can: "agent/update".into(), with: "agent:fleet".into(), constraints: None },
        Capability { can: "agent/reap".into(), with: "agent:fleet".into(), constraints: None },
    ];
    let ucan = issue(&root, root.did(), &caps, 3600, &IssueOptions::default()).expect("ucan");
    (ucan, root.did().to_string())
}

fn spawn_req(ucan: &str, id: &str, caste: Caste) -> SpawnRequest {
    SpawnRequest {
        ucan: ucan.to_string(),
        node: "fake-node".into(),
        id: Some(id.to_string()),
        caste,
        caps: vec!["net".into()],
        lease_secs: 60,
        max_secs: None,
        grant_ttl_secs: DEFAULT_GRANT_TTL_SECS,
        node_args: vec![],
        qspec: None,
        oath: None,
        teleport: None,
    }
}

struct Home {
    path: PathBuf,
}

impl Home {
    fn new(name: &str) -> Home {
        let path = std::env::temp_dir().join(format!("monster-swarm-{name}-{}", std::process::id()));
        let _ = std::fs::remove_dir_all(&path);
        std::fs::create_dir_all(&path).unwrap();
        std::env::set_var("MONSTER_GUARD_HOME", &path);
        let bindir = path.join("bin");
        std::fs::create_dir_all(&bindir).unwrap();
        std::env::set_var("MONSTER_GUARD_BIN", fake_guard(&bindir));
        fake_node(&bindir);
        std::env::set_var("MONSTER_SWARM_NODES", &bindir);
        Home { path }
    }
}

impl Drop for Home {
    fn drop(&mut self) {
        std::env::remove_var("MONSTER_GUARD_HOME");
        std::env::remove_var("MONSTER_GUARD_BIN");
        std::env::remove_var("MONSTER_SWARM_NODES");
        let _ = std::fs::remove_dir_all(&self.path);
    }
}

#[test]
fn real_ops_emit_a_verifiable_chain_in_order() {
    let _env = ENV_GUARD.lock().unwrap_or_else(|e| e.into_inner());
    let _home = Home::new("auditchain");
    let (ucan, spawner) = full_ucan();

    // No ops yet: the chain is empty and trivially verifies.
    let pre = audit::verify();
    assert!(pre.ok, "an empty chain verifies");
    assert_eq!(pre.entries, 0);

    // Drive a representative lifecycle:
    //   spawn(scout) -> spawn(breeder) -> update(scout) -> delegate-spawn ->
    //   reap(scout) -> oath-breach(breeder).
    // The breeder keeps the fleet alive so the scout reap clears homeostasis; the
    // breach overrides the two-queen floor so the breeder can then be revoked.
    ops::spawn(spawn_req(&ucan, "scout1", Caste::Scout)).expect("spawn scout");
    ops::spawn(spawn_req(&ucan, "queen1", Caste::Breeder)).expect("spawn breeder");

    ops::update(UpdateRequest {
        ucan: ucan.clone(),
        id: "scout1".into(),
        caps: Some(vec!["net".into(), "fs".into()]),
        lease_secs: Some(90),
        grant_ttl_secs: DEFAULT_GRANT_TTL_SECS,
    })
    .expect("update scout");

    // Holder-side attenuated delegation of spawn authority (root delegates to a
    // child DID). This mints a child token and emits a Delegate entry.
    let root = store::ensure_root().expect("root");
    let child = a0n_auth::Keypair::generate();
    ops::delegate_spawn(DelegateSpawnRequest {
        parent_ucan: ucan.clone(),
        issuer_secret_hex: root.secret_hex(),
        to_did: child.did().to_string(),
        caps: vec!["net".into()],
        ttl_secs: 600,
    })
    .expect("delegate-spawn");

    ops::reap(&ucan, "scout1").expect("reap scout");

    ops::oath_breach(BreachRequest {
        ucan: ucan.clone(),
        id: "queen1".into(),
        reason: "conduct: the last queen went rogue".into(),
        sig_hex: None,
    })
    .expect("oath-breach breeder");

    // The chain verifies after all that real activity.
    let report = audit::verify();
    assert!(report.ok, "the chain the ops produced verifies: {}", report.reason);

    // Six lifecycle events, in the order they happened, with the right kinds and
    // subjects. The Delegate subject is the CHILD DID; the rest are agent ids.
    let chain = audit::load();
    assert_eq!(chain.len(), 6, "one entry per lifecycle op");
    assert_eq!(report.entries, 6);
    assert_eq!(report.head, chain.last().unwrap().hash, "head is the tip hash");

    // Contiguous seq from 1.
    for (i, e) in chain.iter().enumerate() {
        assert_eq!(e.seq, (i as u64) + 1, "seq is contiguous from 1");
    }

    let kinds: Vec<EventKind> = chain.iter().map(|e| e.kind).collect();
    assert_eq!(
        kinds,
        vec![
            EventKind::Spawn,
            EventKind::Spawn,
            EventKind::Update,
            EventKind::Delegate,
            EventKind::Reap,
            EventKind::Breach,
        ],
        "the EventKinds are present in lifecycle order",
    );

    assert_eq!(chain[0].subject, "scout1");
    assert_eq!(chain[0].actor, spawner, "the spawn actor is the spawner DID");
    assert_eq!(chain[1].subject, "queen1");
    assert_eq!(chain[2].subject, "scout1");
    assert_eq!(chain[3].subject, child.did(), "the delegate subject is the child DID");
    assert_eq!(chain[4].subject, "scout1");
    assert_eq!(chain[5].subject, "queen1");
    assert_eq!(chain[5].detail["reason"], "conduct: the last queen went rogue");
}

#[test]
fn corrupting_audit_jsonl_on_disk_is_detected() {
    let _env = ENV_GUARD.lock().unwrap_or_else(|e| e.into_inner());
    let _home = Home::new("audittamper");
    let (ucan, _spawner) = full_ucan();

    // Produce a small clean chain via real spawns.
    ops::spawn(spawn_req(&ucan, "a", Caste::Scout)).expect("spawn a");
    ops::spawn(spawn_req(&ucan, "b", Caste::Scout)).expect("spawn b");
    ops::spawn(spawn_req(&ucan, "c", Caste::Scout)).expect("spawn c");
    assert!(audit::verify().ok, "precondition: the produced chain verifies");

    let path = audit::audit_path();
    let original = std::fs::read_to_string(&path).expect("read audit.jsonl");
    let mut lines: Vec<String> = original.lines().map(String::from).collect();
    assert_eq!(lines.len(), 3, "three spawn entries on disk");

    // Tamper: rewrite the MIDDLE line's subject in place (a hand edit that
    // bypasses the append path), keeping the line otherwise intact. Its stored
    // hash no longer matches its now-changed content.
    let mut mid: serde_json::Value = serde_json::from_str(&lines[1]).expect("parse line 2");
    assert_eq!(mid["subject"], "b");
    mid["subject"] = serde_json::json!("HACKED");
    lines[1] = serde_json::to_string(&mid).unwrap();
    std::fs::write(&path, format!("{}\n", lines.join("\n"))).unwrap();

    let report = audit::verify();
    assert!(!report.ok, "an on-disk tamper must be detected");
    assert_eq!(report.first_bad, Some(2), "the tampered middle entry (seq 2) is flagged");
    assert_eq!(report.reason, "hash mismatch", "its recomputed hash no longer matches");

    // Restoring the original content makes it verify again — the tamper was the
    // only defect.
    std::fs::write(&path, &original).unwrap();
    assert!(audit::verify().ok, "the restored chain verifies again");
}
